from agent import *from models.products import *debug = Trueimport redef process_revlist(data, context, session):   for rev in data.xpath("//td[@class='list-title']//a"):      url = rev.xpath("@href").string()      title = rev.xpath("descendant::text()").string(multiple=True)      date = rev.xpath("following::td[1]//text()").string(multiple=True)      author = rev.xpath("following::td[2]//text()").string(multiple=True)      if url and title:         name = re_search_once('^(.*) Review', title)         if not(name):            name = title         author = re_search_once('by (.*)$', author)         session.queue(Request(url), process_review, dict(context, url=url, title=title, name=name, date=date, author=author))   next = data.xpath("//li[@class='pagination-next']/a/@href").string()   if next:      session.queue(Request(next), process_revlist, dict(context))def process_review(data, context, session):   product = Product()   product.name = context['name']   product.url = context['url']   product.ssid = re_search_once('\/(\d+)', product.url)   content = data.xpath("//article[@class='item-page']").first()   if content:      product.category = data.xpath("//dl[@class='article-info']/dd[@class='category-name cat-full']//a//text()").string(multiple=True)      if not(product.category):         product.category = 'Game'      product.manufacturer = content.xpath("descendant::span[regexp:test(text(),'Developer')]/following-sibling::node()[1]//text()").string()      review = Review()      review.type = 'pro'      review.title = context['title']      review.url = context['url']      review.ssid = review.title      review.date = context['date']      author = context['author']      if author:         review.authors.append(Person(name=author, ssid=author))      excerpt = content.xpath("p/node()[not(name()='strong')][preceding-sibling::strong[1][regexp:test(text(),'Introduction')]]/descendant-or-self::text()").string(multiple=True)      if not(excerpt):         excerpt = content.xpath("p/node()[not(name()='strong')]/descendant-or-self::text()").string(multiple=True)      if not(excerpt):         excerpt = content.xpath("node()[not(name()='strong' or name()='div')][preceding-sibling::div[@class='jwDisqusArticleCounter'] and following-sibling::div[@class='jwDisqusForm']][preceding-sibling::strong[1][regexp:test(text(),'Introduction')]]/descendant-or-self::text()").string(multiple=True)      if not(excerpt):         excerpt = content.xpath("node()[not(name()='strong' or name()='div')][preceding-sibling::div[@class='jwDisqusArticleCounter'] and following-sibling::div[@class='jwDisqusForm']][count(preceding-sibling::strong)=0]/descendant-or-self::text()").string(multiple=True)      if not(excerpt):         excerpt = content.xpath("node()[not(name()='strong' or name()='div')][preceding-sibling::div[@class='jwDisqusArticleCounter'] and following-sibling::div[@class='jwDisqusForm']][count(preceding-sibling::strong)=1]/descendant-or-self::text()").string(multiple=True)      if not(excerpt):         excerpt = data.xpath("//article[@class='item-page']//p//text()").string(multiple=True)      if excerpt:         review.add_property(type='excerpt', value=excerpt)      lasturl = ''      for page in data.xpath("//ul[@class='nav nav-tabs nav-stacked']/li/a[contains(.,'Page ')]"):         title = page.xpath("descendant::text()").string()         url = page.xpath("@href").string()         if url and title:            lasturl = url            review.add_property(type='pages', value=dict(url=url, title=title))      if lasturl:         session.do(Request(lasturl), process_conclusion, dict(product=product, review=review, excerpt=excerpt))      else:         process_conclusion(data, dict(product=product, review=review, excerpt=excerpt), session)def process_conclusion(data, context, session):   product = context['product']   review = context['review']   content = data.xpath("//article[@class='item-page']").first()   if content:      conclusion = content.xpath("p/node()[not(name()='strong')][preceding-sibling::strong[1][regexp:test(text(),'(Conclusion|Concluding Thoughts)')]]/descendant-or-self::text()").string(multiple=True)      if not(conclusion):         conclusion = content.xpath("p/node()[not(name()='strong')]/descendant-or-self::text()").string(multiple=True)      if not(conclusion):         conclusion = content.xpath("node()[not(name()='strong' or name()='div')][preceding-sibling::div[@class='jwDisqusArticleCounter'] and following-sibling::div[@class='jwDisqusForm']][preceding-sibling::strong[1][regexp:test(text(),'(Conclusion|Concluding Thoughts)')]]/descendant-or-self::text()").string(multiple=True)      if not(conclusion):         conclusion = content.xpath("node()[not(name()='strong' or name()='div')][preceding-sibling::div[@class='jwDisqusArticleCounter'] and following-sibling::div[@class='jwDisqusForm']][count(following-sibling::strong)=0]/descendant-or-self::text()").string(multiple=True)      if not(conclusion):         conclusion = content.xpath("node()[not(name()='strong' or name()='div')][preceding-sibling::div[@class='jwDisqusArticleCounter'] and following-sibling::div[@class='jwDisqusForm']]/descendant-or-self::text()").string(multiple=True)      if not(conclusion):         conclusion = data.xpath("//article[@class='item-page']/following-sibling::p[contains(.,'Conclusion')]//text()").string(multiple=True)         if conclusion:            conclusion = conclusion.split('Conclusion')[1]      if not conclusion:         conclusion = data.xpath("//article[@class='item-page']/p[contains(.,'Conclusion')]/following-sibling::p//text()").string(multiple=True)      if conclusion:         review.add_property(type='conclusion', value=conclusion)      rate = data.xpath("//span[@class='gb10bold' and regexp:test(normalize-space(.), '^Overall$')]/following::text()[normalize-space(self::text())][1]").string()      if rate:         review.grades.append(Grade(type='overall', name='Overall', value=float(rate), best=10.0))      for g in data.xpath("//img[regexp:test(@src, '/\d+\.\d+\.gif$')]"):         name = g.xpath("preceding::text()[normalize-space(self::text())][1]").string()         ratetxt = g.xpath("@src").string()         if name and ratetxt:            rate = re_search_once("/(\d+\.\d+)", ratetxt)            if rate:               review.grades.append(Grade(name=name, value=float(rate), best=10.0))   if context['excerpt'] or conclusion:      product.reviews.append(review)      session.emit(product)def run(context, session):   session.queue(Request('http://www.gamebanshee.com/reviews/'), process_revlist, {})   ##session.queue(Request('http://www.gamebanshee.com/sitefeatures/previews.php'), process_frontpage, dict(is_preview=True))